module shift_register_8bit (
    input wire clk,
    input wire load,
    input wire [7:0] data_in,
    input wire shift_in,
    output reg [7:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (load)
            q <= data_in;
        else
            q <= {q[6:0], shift_in};
    end

endmodule
